import pytest

@pytest.fixture
def database():
    conn = create_connection()
    yield conn
    conn.close()

@pytest.mark.parametrize("input,expected", [
    ("hello", 5),
    ("world", 5),
    ("", 0),
], ids=["word", "word2", "empty"])
def test_length(database, input, expected):
    result = database.query(f"SELECT LENGTH('{input}')")
    assert result == expected

import unittest

class TestDatabase(unittest.TestCase):
    def setUp(self):
        self.conn = create_connection()

    def tearDown(self):
        self.conn.close()

    def test_length_hello(self):
        result = self.conn.query("SELECT LENGTH('hello')")
        self.assertEqual(result, 5)

    def test_length_world(self):
        result = self.conn.query("SELECT LENGTH('world')")
        self.assertEqual(result, 5)

@pytest.fixture(scope="module")
def database():
    # Expensive: connect once per test file
    conn = create_connection()
    yield conn
    conn.close()

@pytest.fixture
def transaction(database):
    # Fast: begin/rollback per test
    database.begin()
    yield database
    database.rollback()

def test_insert(transaction):
    transaction.insert("users", {"name": "Alice"})
    assert transaction.count("users") == 1

@pytest.fixture(scope="session")
def shared_counter():
    return {"count": 0}

def test_a(shared_counter):
    shared_counter["count"] += 1

def test_b(shared_counter):
    # depends on test_a running first; fails with --randomly
    assert shared_counter["count"] == 1

