import pytest
from app import create_app

@pytest.fixture
def app():
    app = create_app(config="test")
    app.config["TESTING"] = True
    return app

@pytest.fixture
def client(app):
    return app.test_client()

@pytest.fixture
def db(app):
    with app.app_context():
        db.create_all()
        yield db
        db.session.remove()
        db.drop_all()
